div.div:
useConnectionStatus = create((set) => ({
statuses: {
"sse:vibe": { state: "connecting", since: timestamp },
"sse:bgm": { state: "open", since: timestamp },
"sse:murmur": { state: "open", since: timestamp },
"ws:hallway": { state: "closed", since: timestamp },
},
setStatus(key, state) {
set((s) => ({
statuses: { ...s.statuses, [key]: { state, since: Date.now() } },
}))
},
}))
